// entity 1 — player spawn (BAY 1, west; facing +X toward the dummy line). Tagged
// `player`, the EXCLUSIVE target of the combat-demo-reaction.ts `applyDamage`
// reaction. The player archetype declares health (max 100) but NO hitbox, so this
// tag is never matched by a weapon ray — only by the named retaliation reaction.
// The enemy (entity 7) is in BAY 3 behind two offset walls, so reaching the
// player requires routing through door A then door B (A* corridor + funnel).
{
"classname" "player_spawn"
"origin" "48 128 24"
"angles" "0 0 0"
"_tags" "player"
}
// entity 2 — target dummy (BAY 1, in front of the player so the reference pistol's
// hitscan ray can reach it). Carries health (max 30) + hitbox; three 12-damage
// hits despawn it. Tagged `dummy` (EXCLUSIVE to the dummies) so it counts toward
// the progress threshold.
{
"classname" "target_dummy"
"origin" "128 64 16"
"angles" "0 180 0"
"_tags" "dummy"
}
// entity 3 — target dummy.
{
"classname" "target_dummy"
"origin" "128 112 16"
"angles" "0 180 0"
"_tags" "dummy"
}
// entity 4 — target dummy.
{
"classname" "target_dummy"
"origin" "128 160 16"
"angles" "0 180 0"
"_tags" "dummy"
}
// entity 5 — target dummy. Four dummies, fraction 0.5 means two kills fire
// `dummiesCleared`, which routes 35 damage to the `player` tag.
{
"classname" "target_dummy"
"origin" "128 208 16"
"angles" "0 180 0"
"_tags" "dummy"
}
// entity 6 — light over BAY 1 (player + dummies)
{
"classname" "light"
"origin" "96 128 100"
"light" "300"
"_falloff_range" "2048"
}
// entity 8 — light over BAY 2 (the corridor between the walls)
{
"classname" "light"
"origin" "256 128 100"
"light" "300"
"_falloff_range" "2048"
}
// entity 9 — light over BAY 3 (the enemy)
{
"classname" "light"
"origin" "432 128 100"
"light" "300"
"_falloff_range" "2048"
}
// entity 7 — M10 reference enemy (BAY 3, east). Map-placeable via `"classname"
// "reference_enemy"` because its descriptor (sdk/behaviors/reference/entities.ts,
// spread into the dev mod through `...referenceEntities`) carries health + mesh.
// It also carries the `ai` brain (detection/attack/leash, attackDamage,
// attackCooldownMs, moveSpeed, deathDespawnMs, and the idle/alert/attack/death
// -> mesh-state map). The CC0 KayKit Knight model animates the four FSM states.
// Placed in BAY 3 so reaching the player requires the A* corridor + funnel route
// (door B then door A); the shipped reference pistol's hitscan kills it
// (health max 60 + hitbox).
{
"classname" "reference_enemy"
"origin" "464 128 16"
"angles" "0 180 0"
"_tags" "enemy"
}
